    with open(business_file, 'r') as f:
        businesses = json.load(f)
else:
    businesses = business_file

print(f"Loaded {len(businesses)} businesses")

# Define US state codes
us_states = {'AL', 'AK', 'AZ', 'AR', 'CA', 'CO', 'CT', 'DE', 'FL', 'GA', 
             'HI', 'ID', 'IL', 'IN', 'IA', 'KS', 'KY', 'LA', 'ME', 'MD', 
             'MA', 'MI', 'MN', 'MS', 'MO', 'MT', 'NE', 'NV', 'NH', 'NJ', 
             'NM', 'NY', 'NC', 'ND', 'OH', 'OK', 'OR', 'PA', 'RI', 'SC', 
             'SD', 'TN', 'TX', 'UT', 'VT', 'VA', 'WA', 'WV', 'WI', 'WY'}

# Extract state from description
def extract_state(desc):
    if not desc or not isinstance(desc, str):
        return None
    # Find state-like patterns
    patterns = [
        r'in\s+[^,]*,\s*([A-Z]{2})\b',
        r'([A-Z]{2})\b[^A-Za-z]*$',
        r'\bin\s+([A-Z]{2})\b'
    ]
    for pat in patterns:
        m = re.search(pat, desc)
        if m and m.group(1) in us_states:
            return m.group(1)
    return None

state_reviews = {}
state_businesses = {}
processed = 0

for b in businesses:
    desc = b.get('description', '')
    state = extract_state(desc)
    if state:
        # Get review_count field
        review_count = b.get('review_count')
        # Convert to int if it's a string
        try:
            if isinstance(review_count, str):
                review_count = int(review_count)
            elif review_count is None:
                review_count = 0
        except:
            review_count = 0

        state_reviews[state] = state_reviews.get(state, 0) + review_count
        state_businesses[state] = state_businesses.get(state, 0) + 1

    processed += 1
    if processed % 50 == 0:
        print(f"Processed {processed}...")

# Find state with most reviews
if state_reviews:
    top_state = max(state_reviews.items(), key=lambda x: x[1])
    print(f"\nTop state: {top_state[0]} with {top_state[1]} reviews")
    print(f"State counts: {state_reviews}")

    # Get businesses in this state
    state_businesses_list = []
    for b in businesses:
        desc = b.get('description', '')
        state = extract_state(desc)
        if state == top_state[0]:
            state_businesses_list.append(b)

    print(f"Businesses in {top_state[0]}: {len(state_businesses_list)}")
else:
    top_state = (None, 0)

print('__RESULT__:')
print(json.dumps({
    'top_state': top_state[0],
    'top_state_reviews': top_state[1],
    'state_reviews': state_reviews
}))"}

