# Extract state from description
def extract_state(desc):
    if not desc or not isinstance(desc, str):
        return None
    # Look for 2-letter codes that are valid states
    for word in desc.split():
        if len(word) == 2 and word in us_states:
            return word
    # Alternative: look for patterns like "in City, ST," or "City, ST location"
    match = re.search(r'[,\s]([A-Z]{2})[,\s]', desc)
    if match and match.group(1) in us_states:
        return match.group(1)
    return None

# Extract data
state_reviews = {}
state_businesses = {}

for b in businesses:
    desc = b.get('description', '[no description]')
    state = extract_state(desc)
    review_count = b.get('review_count', 0)

    # Convert review_count to int
    try:
        if isinstance(review_count, str):
            review_count = int(review_count)
        elif review_count is None:
            review_count = 0
    except:
        review_count = 0

    if state:
        state_reviews[state] = state_reviews.get(state, 0) + review_count
        state_businesses[state] = state_businesses.get(state, 0) + 1
        print(f"Found: {state} - {review_count} reviews - {desc[:50]}...")

# Find top state
