    sorted_states = sorted(state_reviews.items(), key=lambda x: x[1], reverse=True)
    top_state = sorted_states[0]
    print(f"\nTop state: {top_state[0]} with {top_state[1]} reviews")
    print(f"All states: {state_reviews}")
else:
    top_state = (None, 0)
    print("No states found")

result = {
    'top_state': top_state[0],
    'top_state_reviews': top_state[1],
